// Extract text from document based on file type
const document = $input.first().json;
const binaryData = $input.first().binary;

let extractedText = '';
const mimeType = document.mime_type;

// For text-based files, read content directly
if (mimeType === 'text/plain' || mimeType === 'application/json' || mimeType === 'application/xml' || mimeType === 'text/csv') {
  if (binaryData && binaryData.data) {
    extractedText = binaryData.data.toString('utf-8').substring(0, 10000); // Limit to 10KB for classification
  }
}
// For images and PDFs, in production we would use OCR
// For this implementation, we'll use filename and metadata as fallback
else {
  extractedText = document.original_filename || '';
  if (document.metadata) {
    extractedText += ' ' + JSON.stringify(document.metadata);
  }
}

// Get client classification rules from config
// This would typically come from client_config table
const classificationRules = {
  categories: ['invoice', 'contract', 'resume', 'report', 'form', 'receipt', 'letter', 'other'],
  priorityLevels: ['low', 'medium', 'high', 'urgent'],
  confidenceThreshold: 0.7
};

// Prepare data for LLM classification
const classificationData = {
  document_id: document.document_id,
  document_uuid: document.document_uuid,
  client_id: document.client_id,
  filename: document.original_filename,
  mime_type: document.mime_type,
  document_type: document.document_type,
  content_preview: extractedText,
  classification_rules: classificationRules,
  timestamp: new Date().toISOString()
};

return [{ json: classificationData }];

// Simulate LLM classification
// In production, this would call OpenAI or similar API
const data = $input.first().json;
const filename = data.filename.toLowerCase();
const content = data.content_preview.toLowerCase();

// Simple keyword-based classification (fallback if LLM not available)
let category = 'other';
let confidence = 0.6;
let priority = 'medium';
let tags = [];
let keywords = [];

// Classification logic
if (filename.includes('invoice') || content.includes('invoice') || content.includes('bill')) {
  category = 'invoice';
  confidence = 0.85;
  priority = 'high';
  tags = ['financial', 'payment'];
  keywords = ['invoice', 'bill', 'amount', 'total', 'due'];
} else if (filename.includes('contract') || content.includes('contract') || content.includes('agreement')) {
  category = 'contract';
  confidence = 0.88;
  priority = 'high';
  tags = ['legal', 'binding'];
  keywords = ['contract', 'agreement', 'terms', 'conditions'];
} else if (filename.includes('resume') || filename.includes('cv') || content.includes('experience') || content.includes('education')) {
  category = 'resume';
  confidence = 0.90;
  priority = 'medium';
  tags = ['hr', 'hiring'];
  keywords = ['resume', 'experience', 'education', 'skills'];
} else if (filename.includes('report') || content.includes('report') || content.includes('analysis')) {
  category = 'report';
  confidence = 0.75;
  priority = 'medium';
  tags = ['business', 'analysis'];
  keywords = ['report', 'analysis', 'summary', 'findings'];
} else if (filename.includes('form') || content.includes('application') || content.includes('signature')) {
  category = 'form';
  confidence = 0.72;
  priority = 'low';
  tags = ['administrative'];
  keywords = ['form', 'application', 'signature', 'fields'];
} else if (filename.includes('receipt') || content.includes('receipt') || content.includes('purchase')) {
  category = 'receipt';
  confidence = 0.80;
  priority = 'low';
  tags = ['financial', 'expense'];
  keywords = ['receipt', 'purchase', 'amount', 'date'];
} else if (filename.includes('letter') || content.includes('dear') || content.includes('sincerely')) {
  category = 'letter';
  confidence = 0.68;
  priority = 'low';
  tags = ['correspondence'];
  keywords = ['letter', 'dear', 'sincerely', 'regards'];
}

// Add content-based tags
if (content.includes('confidential') || content.includes('private')) {
  tags.push('confidential');
  if (priority !== 'urgent') priority = 'high';
}
if (content.includes('urgent') || content.includes('asap')) {
  priority = 'urgent';
}

// Classification result
const result = {
  document_id: data.document_id,
  document_uuid: data.document_uuid,
  client_id: data.client_id,
  classification: {
    category: category,
    confidence: confidence,
    priority: priority,
    tags: tags,
    keywords: keywords
  },
  classification_method: 'keyword_based', // In production: 'llm_based'
  classified_at: new Date().toISOString()
};

return [{ json: result }];
